#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N,M; scanf("%d %d", &N, &M);
        char **g = (char**)malloc(N*sizeof(char*));
        for(int i=0;i<N;i++){
            g[i]= (char*)malloc((M+1)*sizeof(char));
            scanf("%s", g[i]);
        }
        long long ans=0;
        int maxd = (N<M?N:M)-1;
        for(int d=2; d<=maxd; ++d){
            for(int i=0; i+d-1<N; ++i){
                for(int j=0; j+d-1<M; ++j){
                    char c = g[i][j];
                    if(c==g[i][j+d-1] && c==g[i+d-1][j] && c==g[i+d-1][j+d-1])
                        ++ans;
                }
            }
        }
        printf("%lld\n", ans);
        for(int i=0;i<N;i++) free(g[i]);
        free(g);
    }
    return 0;
}

