import sys
def solve():
    data = sys.stdin.read().splitlines()
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N, M = map(int, next(it).split())
        grid = [list(next(it).strip()) for _ in range(N)]
        ans = 0
        maxd = min(N, M) - 1
        for d in range(2, maxd + 1):
            for i in range(N - d + 1):
                row_i = grid[i]
                row_id = grid[i + d - 1]
                for j in range(M - d + 1):
                    c = row_i[j]
                    if c == row_i[j + d - 1] and c == row_id[j] and c == row_id[j + d - 1]:
                        ans += 1
        out.append(str(ans))
    sys.stdout.write('\n'.join(out))
if __name__ == "__main__":
    solve()

